import React, { useState } from 'react';
import { fetchEventData } from '../services/ftcScoutApi';

const EventSearch: React.FC = () => {
    const [eventName, setEventName] = useState('');
    const [eventData, setEventData] = useState(null);
    const [error, setError] = useState('');

    const handleSearch = async () => {
        if (!eventName) {
            setError('Please enter an event name.');
            return;
        }
        setError('');
        try {
            const data = await fetchEventData(eventName);
            setEventData(data);
        } catch (err) {
            setError('Error fetching event data. Please try again.');
        }
    };

    return (
        <div>
            <h1>Search for FIRST Tech Challenge Event</h1>
            <input
                type="text"
                value={eventName}
                onChange={(e) => setEventName(e.target.value)}
                placeholder="Enter event name"
            />
            <button onClick={handleSearch}>Search</button>
            {error && <p style={{ color: 'red' }}>{error}</p>}
            {eventData && (
                <div>
                    <h2>{eventData.name}</h2>
                    <p>Location: {eventData.location}</p>
                    <p>Date: {eventData.date}</p>
                    {/* Additional components to display matches and rankings can be added here */}
                </div>
            )}
        </div>
    );
};

export default EventSearch;
